import { randomUUID } from 'node:crypto';

import type { INote } from '@interfaces/note.interface';

import type { Collection, Db } from 'mongodb';

export class NoteModel {
	private collection: Collection<INote>;

	constructor(db: Db) {
		this.collection = db.collection<INote>('notes');
		this.initializeCollection().catch((error: unknown) => {
			/* eslint-disable-next-line no-console */
			console.error('Failed to initialize notes collection:', error);
		});
	}

	private async initializeCollection(): Promise<void> {
		// Create indexes
		await this.collection.createIndex({ id: 1 }, { unique: true });
		await this.collection.createIndex({ folderId: 1 });
		await this.collection.createIndex({ title: 1 });
		await this.collection.createIndex({ updatedAt: -1 });

		await this.collection.db.command({
			collMod: 'notes',
			validator: {
				$jsonSchema: {
					bsonType: 'object',
					required: ['id', 'title', 'content', 'createdAt', 'updatedAt'],
					properties: {
						id: {
							bsonType: 'string',
							description: 'Unique identifier for the note',
						},
						title: {
							bsonType: 'string',
							minLength: 1,
							maxLength: 500,
							description: 'Note title',
						},
						content: {
							bsonType: 'string',
							description: 'Note content in Markdown format',
						},
						folderId: {
							bsonType: ['string', 'null'],
							description: 'Parent folder ID or null for root notes',
						},
						createdAt: {
							bsonType: 'date',
							description: 'Creation timestamp',
						},
						updatedAt: {
							bsonType: 'date',
							description: 'Last update timestamp',
						},
					},
				},
			},
			validationLevel: 'strict',
			validationAction: 'error',
		});
	}

	public async create(
		title: string,
		content: string,
		folderId: string | null,
	): Promise<INote> {
		const note: INote = {
			id: randomUUID(),
			title,
			content,
			folderId,
			createdAt: new Date(),
			updatedAt: new Date(),
		};

		await this.collection.insertOne(note);
		return note;
	}

	public async findById(id: string): Promise<INote | null> {
		return this.collection.findOne({ id });
	}

	public async findAll(): Promise<INote[]> {
		return this.collection.find({}).sort({ updatedAt: -1 }).toArray();
	}

	public async findByFolderId(folderId: string | null): Promise<INote[]> {
		return this.collection.find({ folderId }).sort({ updatedAt: -1 }).toArray();
	}

	public async update(id: string, updates: Partial<INote>): Promise<INote | null> {
		const result = await this.collection.findOneAndUpdate(
			{ id },
			{ $set: { ...updates, updatedAt: new Date() } },
			{ returnDocument: 'after' },
		);

		return result ?? null;
	}

	public async delete(id: string): Promise<boolean> {
		const result = await this.collection.deleteOne({ id });
		return result.deletedCount === 1;
	}

	public async countByFolderId(folderId: string | null): Promise<number> {
		return this.collection.countDocuments({ folderId });
	}
}

