import { getNoteModel } from '@config/db-connection.config';

import type {
	ICreateNotePayload,
	IDeleteNotePayload,
	IMoveNotePayload,
	INote,
	IRenameNotePayload,
	IUpdateNotePayload,
} from '@interfaces/note.interface';

class NoteService {
	public async createNote(payload: ICreateNotePayload): Promise<INote> {
		const model = getNoteModel();
		return model.create(payload.title, payload.content, payload.folderId);
	}

	public async deleteNote(payload: IDeleteNotePayload): Promise<boolean> {
		const model = getNoteModel();

		const note = await model.findById(payload.id);
		if (!note) {
			throw new Error('Note not found');
		}

		return model.delete(payload.id);
	}

	public async renameNote(payload: IRenameNotePayload): Promise<INote> {
		const model = getNoteModel();

		const note = await model.findById(payload.id);
		if (!note) {
			throw new Error('Note not found');
		}

		const updated = await model.update(payload.id, { title: payload.title });
		if (!updated) {
			throw new Error('Failed to rename note');
		}

		return updated;
	}

	public async updateNote(payload: IUpdateNotePayload): Promise<INote> {
		const model = getNoteModel();

		const note = await model.findById(payload.id);
		if (!note) {
			throw new Error('Note not found');
		}

		const updated = await model.update(payload.id, { content: payload.content });
		if (!updated) {
			throw new Error('Failed to update note');
		}

		return updated;
	}

	public async moveNote(payload: IMoveNotePayload): Promise<INote> {
		const model = getNoteModel();

		const note = await model.findById(payload.id);
		if (!note) {
			throw new Error('Note not found');
		}

		const updated = await model.update(payload.id, { folderId: payload.folderId });
		if (!updated) {
			throw new Error('Failed to move note');
		}

		return updated;
	}

	public async getAllNotes(): Promise<INote[]> {
		const model = getNoteModel();
		return model.findAll();
	}

	public async getNote(id: string): Promise<INote | null> {
		const model = getNoteModel();
		return model.findById(id);
	}

	public async getNotesByFolder(folderId: string | null): Promise<INote[]> {
		const model = getNoteModel();
		return model.findByFolderId(folderId);
	}
}

export const noteService = new NoteService();

