import { getFolderModel } from '@config/db-connection.config';

import type {
	ICreateFolderPayload,
	IDeleteFolderPayload,
	IFolder,
	IMoveFolderPayload,
	IRenameFolderPayload,
} from '@interfaces/folder.interface';

class FolderService {
	public async createFolder(payload: ICreateFolderPayload): Promise<IFolder> {
		const model = getFolderModel();
		return model.create(payload.name, payload.parentId);
	}

	public async deleteFolder(payload: IDeleteFolderPayload): Promise<boolean> {
		const model = getFolderModel();

		const folder = await model.findById(payload.id);
		if (!folder) {
			throw new Error('Folder not found');
		}

		// Check if folder has children
		const hasChildren = await model.hasChildren(payload.id);
		if (hasChildren) {
			throw new Error('Cannot delete folder with children');
		}

		return model.delete(payload.id);
	}

	public async renameFolder(payload: IRenameFolderPayload): Promise<IFolder> {
		const model = getFolderModel();

		const folder = await model.findById(payload.id);
		if (!folder) {
			throw new Error('Folder not found');
		}

		const updated = await model.update(payload.id, { name: payload.name });
		if (!updated) {
			throw new Error('Failed to rename folder');
		}

		return updated;
	}

	public async moveFolder(payload: IMoveFolderPayload): Promise<IFolder> {
		const model = getFolderModel();

		const folder = await model.findById(payload.id);
		if (!folder) {
			throw new Error('Folder not found');
		}

		// Prevent moving folder into itself or its descendants
		if (payload.parentId) {
			if (payload.parentId === payload.id) {
				throw new Error('Cannot move folder into itself');
			}

			const isDescendant = await this.isDescendant(payload.id, payload.parentId);
			if (isDescendant) {
				throw new Error('Cannot move folder into its descendant');
			}
		}

		const updated = await model.update(payload.id, { parentId: payload.parentId });
		if (!updated) {
			throw new Error('Failed to move folder');
		}

		return updated;
	}

	public async getAllFolders(): Promise<IFolder[]> {
		const model = getFolderModel();
		return model.findAll();
	}

	public async getFolder(id: string): Promise<IFolder | null> {
		const model = getFolderModel();
		return model.findById(id);
	}

	private async isDescendant(ancestorId: string, descendantId: string): Promise<boolean> {
		const model = getFolderModel();
		let current = await model.findById(descendantId);

		while (current) {
			if (current.parentId === ancestorId) {
				return true;
			}
			if (!current.parentId) {
				return false;
			}
			current = await model.findById(current.parentId);
		}

		return false;
	}
}

export const folderService = new FolderService();

