import { Server, type Socket } from 'socket.io';

import { registerFolderHandlers } from '@modules/websocket/handlers/folder.handler';
import { registerNoteHandlers } from '@modules/websocket/handlers/note.handler';
import { registerSyncHandlers } from '@modules/websocket/handlers/sync.handler';

import { SOCKET_EVENTS } from '@constants/socket.constants';

import type {
	IClientToServerEvents,
	IServerToClientEvents,
} from '@interfaces/socket-events.interface';

import type { Server as HttpServer } from 'node:http';

export type TypedSocket = Server<IClientToServerEvents, IServerToClientEvents>;
export type TypedServerSocket = Socket<IClientToServerEvents, IServerToClientEvents>;

export function createWebSocketServer(httpServer: HttpServer): TypedSocket {
	const io = new Server<IClientToServerEvents, IServerToClientEvents>(httpServer, {
		cors: {
			origin: '*', // Configure this properly in production
			methods: ['GET', 'POST'],
		},
		pingTimeout: 60000,
		pingInterval: 25000,
	});

	io.on(SOCKET_EVENTS.TECHNICAL.CONNECT, (socket) => {
		/* eslint-disable-next-line no-console */
		console.log(`Client connected: ${socket.id}`);

		// Register all event handlers
		registerFolderHandlers(io, socket);
		registerNoteHandlers(io, socket);
		registerSyncHandlers(io, socket);

		socket.on(SOCKET_EVENTS.TECHNICAL.DISCONNECT, (reason) => {
			/* eslint-disable-next-line no-console */
			console.log(`Client disconnected: ${socket.id}, reason: ${reason}`);
		});
	});

	return io;
}
